function setRepoStats(e,t){let n=`https://api.github.com/repos/inviro/${e}`;fetch(n,{method:"GET",headers:{Accept:"application/json","Content-Type":"application/json","User-Agent":"AbrahamChen.me"}}).then(e=>e.json()).then(e=>{document.getElementById(`watch-${t}`).innerHTML=` ${e.watchers_count}`,document.getElementById(`star-${t}`).innerHTML=` ${e.stargazers_count}`,document.getElementById(`fork-${t}`).innerHTML=` ${e.forks_count}`,document.getElementById(`caption-${t}`).innerHTML=` ${e.description}`})}function loadProject(e){let t=document.getElementById(e),n=t.firstElementChild.innerHTML,a=e.split("-")[1],i=`<a href = 'https://github.com/inviro/${n}'>${n}</a>`;t.firstElementChild.innerHTML=i,i=`<a href="https://github.com/inviro/${n}/watchers" aria-label = "${n} Watchers"><i class="fa fa-lg fa-eye" id="watch-${a}"></i></a>`,i+=`<a href="https://github.com/inviro/${n}/stargazers" aria-label = "${n} Stargazers"><i class="fa fa-lg fa-star" id="star-${a}"></i></a>`,i+=`<a href="https://github.com/inviro/${n}/network/members" aria-label = "${n} Forks"><i class="fa fa-lg fa-code-branch" id="fork-${a}"></i></a>`,document.getElementById(`repo-stats-${a}`).innerHTML=i,setRepoStats(n,a)}function loadProjects(){let e=document.getElementsByClassName("project");for(let t=0;t<e.length;t++)loadProject(`project-${t}`)}function setThemeLight(){let e=document.documentElement;e.style.setProperty("--primary-color","3, 4, 94"),e.style.setProperty("--overlay-color","rgba(245, 250, 255, 0.95)"),e.style.setProperty("--header-color","33, 158, 188"),e.style.setProperty("--highlight-color","rgba(255, 255, 255, .90)")}function setThemeDark(){let e=document.documentElement;e.style.setProperty("--primary-color","255, 255, 255"),e.style.setProperty("--overlay-color","rgba(50, 50, 140, .5)"),e.style.setProperty("--header-color","3, 4, 94"),e.style.setProperty("--highlight-color","#219EBC")}function addThemePicker(){document.getElementById("theme-light").checked=!0,document.getElementById("color-theme").style.display="inline",document.getElementById("theme-light").onclick=setThemeLight,document.getElementById("theme-dark").onclick=setThemeDark}function addAnimations(){let e=document.getElementsByClassName("logo")[0];e.addEventListener("mouseover",()=>{e.style.animation="rotation 2s infinite linear"}),e.addEventListener("mouseout",()=>{e.style.animation="none"})}function addTextAnimation(e,t){if(t.indexOf(" | ")>-1){let n=!1,a=t.split(" | "),i=0;setInterval(()=>{n||(e.innerHTML=a[i],i=(i+1)%a.length)},4500),e.addEventListener("mouseover",()=>{n=!0}),e.addEventListener("mouseout",()=>{n=!1})}}function updateHitCount(){let e=document.getElementById("visits-display");fetch(atob("aHR0cHM6Ly91cy1jZW50cmFsMS1hYnJhaGFtY2hlbndlYi5jbG91ZGZ1bmN0aW9ucy5uZXQvd2Vic2l0ZUhpdHMg")).then(e=>e.json()).then(t=>{let n=`<p><strong>Weekly visits:  </strong>${parseInt(t.weeklyHits,10).toLocaleString()}`;n+=`<br><strong>Total visits:  </strong>${parseInt(t.totalHits,10).toLocaleString()}</p>`,e.innerHTML=n})}let canvas,ctx,particles=[],cursorX=-9999,cursorY=-9999;function initParticles(){ctx=(canvas=document.getElementById("particle-canvas")).getContext("2d"),canvas.width=window.innerWidth,canvas.height=window.innerHeight;for(let e=0;e<100;e++)particles.push({x:Math.random()*canvas.width,y:Math.random()*canvas.height,vx:(Math.random()-.5)*2,vy:(Math.random()-.5)*2,size:10*Math.random()+1,color:`rgba(255, 255, 255, ${Math.random()})`});window.addEventListener("resize",()=>{canvas.width=window.innerWidth,canvas.height=window.innerHeight}),window.addEventListener("mousemove",e=>{let t=getMousePos(canvas,e);cursorX=t.x,cursorY=t.y}),window.addEventListener("mousedown",e=>{let t=getMousePos(canvas,e);for(let n=0;n<20;n++)particles.push({x:t.x,y:t.y,vx:(Math.random()-.5)*4,vy:(Math.random()-.5)*4,size:10*Math.random()+1,color:`rgba(255, 255, 255, ${Math.random()})`})}),animateParticles()}function getMousePos(e,t){let n=e.getBoundingClientRect();return{x:t.clientX-n.left,y:t.clientY-n.top}}function animateParticles(){ctx.clearRect(0,0,canvas.width,canvas.height),particles.forEach(e=>{e.x+=e.vx,e.y+=e.vy,(e.x<0||e.x>canvas.width)&&(e.vx*=-1),(e.y<0||e.y>canvas.height)&&(e.vy*=-1);let t=e.x-cursorX,n=e.y-cursorY,a=Math.sqrt(t*t+n*n);if(a<e.size&&(e.vx*=-1,e.vy*=-1,a>0)){let i=e.size-a+5;e.x+=t/a*i,e.y+=n/a*i}ctx.beginPath(),ctx.arc(e.x,e.y,e.size,0,2*Math.PI),ctx.fillStyle=e.color,ctx.fill()}),requestAnimationFrame(animateParticles)}window.onload=()=>{updateHitCount(),addThemePicker(),addAnimations(),loadProjects(),initParticles()};